import{_ as e,o as t,c as a,O as r}from"./chunks/framework.bdcb0ee1.js";const y=JSON.parse('{"title":"Security Logs","description":"","frontmatter":{},"headers":[],"relativePath":"administration/advanced/security-logs.md","filePath":"administration/advanced/security-logs.md","lastUpdated":1773166296000}'),i={name:"administration/advanced/security-logs.md"},s=r('<h1 id="security-logs" tabindex="-1">Security Logs <a class="header-anchor" href="#security-logs" aria-label="Permalink to &quot;Security Logs&quot;">​</a></h1><p>Security logs provide an audit trail of authentication and account-related events on your board. They help administrators monitor suspicious activity and investigate potential security issues.</p><p>You can view security logs from the <strong>Advanced</strong> section in the Admin Control Panel.</p><nav class="table-of-contents"><ul><li><a href="#viewing-logs">Viewing Logs</a></li><li><a href="#event-types">Event Types</a></li><li><a href="#filtering">Filtering</a></li><li><a href="#privacy">Privacy</a></li><li><a href="#notes">Notes</a></li></ul></nav><h2 id="viewing-logs" tabindex="-1">Viewing Logs <a class="header-anchor" href="#viewing-logs" aria-label="Permalink to &quot;Viewing Logs&quot;">​</a></h2><p>The security log displays a chronological list of events, with the most recent entries shown first. Each log entry includes:</p><ul><li><strong>Event Type</strong>: The type of action that occurred.</li><li><strong>User</strong>: The user associated with the event (if applicable).</li><li><strong>Date</strong>: When the event occurred.</li></ul><p>Logs are paginated at 50 entries per page.</p><h2 id="event-types" tabindex="-1">Event Types <a class="header-anchor" href="#event-types" aria-label="Permalink to &quot;Event Types&quot;">​</a></h2><p>The following event types are tracked:</p><table><thead><tr><th>Event</th><th>Description</th></tr></thead><tbody><tr><td>Login</td><td>A user successfully logged in.</td></tr><tr><td>Logout</td><td>A user logged out.</td></tr><tr><td>Registered</td><td>A new user account was created.</td></tr><tr><td>Password Reset</td><td>A user requested a password reset.</td></tr><tr><td>Password Changed</td><td>A user changed their password.</td></tr><tr><td>Email Changed</td><td>A user changed their email address.</td></tr><tr><td>Account Deleted</td><td>A user account was removed.</td></tr><tr><td>Lockout</td><td>A user was locked out after too many failed login attempts.</td></tr></tbody></table><h2 id="filtering" tabindex="-1">Filtering <a class="header-anchor" href="#filtering" aria-label="Permalink to &quot;Filtering&quot;">​</a></h2><p>You can filter the log by event type using the dropdown at the top of the page. This is useful for quickly finding specific types of events, such as all failed login attempts or recent registrations.</p><h2 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h2><p>For privacy and security reasons, certain sensitive information is not displayed to board administrators:</p><ul><li><strong>IP addresses</strong> are not shown in the admin view.</li><li><strong>Email addresses</strong> and related metadata (such as old and new email addresses during an email change) are hidden.</li></ul><p>This ensures that board administrators cannot access personal data unnecessarily. Full log details are only available to platform super-administrators.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Security logs are created automatically whenever a tracked event occurs. No configuration is required.</li><li>Logs are retained according to the platform&#39;s data retention policy. Older entries are pruned periodically.</li><li>Security logs are read-only. They cannot be edited or deleted by board administrators.</li></ul>',19),o=[s];function n(d,l,c,h,u,g){return t(),a("div",null,o)}const f=e(i,[["render",n]]);export{y as __pageData,f as default};
